// ─── STATE ───────────────────────────────────────────────
let currentTrack = parseInt(localStorage.getItem('qm_track')) || 30;
let currentDay = 1;

// ─── SEARCH ──────────────────────────────────────────────
let searchIndex = null;
let searchActiveIdx = -1;

function buildSearchIndex() {
  searchIndex = [];
  const trackDays = [
    { track: 30, days: DAYS_30 },
    { track: 90, days: DAYS_90 },
    { track: 180, days: DAYS_180 }
  ];
  // Build from current track
  const days = getTrackDays();
  const len = getTrackLength();
  for (let i = 1; i <= len; i++) {
    const d = days[i];
    if (!d) continue;
    const mod = MODULES[d.module - 1];
    // Strip HTML for search text
    const strip = (html) => (html || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
    const searchText = [
      d.title,
      mod.name,
      strip(d.concept),
      strip(d.example),
      strip(d.poker),
      ...(d.problems || []).map(p => p.q + ' ' + p.a)
    ].join(' ').toLowerCase();
    searchIndex.push({
      day: i,
      title: d.title,
      module: mod.name,
      moduleId: d.module,
      searchText: searchText
    });
  }
}

function openSearch() {
  if (!searchIndex) buildSearchIndex();
  document.getElementById('search-overlay').style.display = 'flex';
  const input = document.getElementById('search-input');
  input.value = '';
  input.focus();
  searchActiveIdx = -1;
  document.getElementById('search-results').innerHTML = '<div class="search-hint">Type to search across all days and concepts</div>';
}

function closeSearch() {
  document.getElementById('search-overlay').style.display = 'none';
}

function onSearchInput(query) {
  const q = query.trim().toLowerCase();
  const container = document.getElementById('search-results');
  if (!q) {
    container.innerHTML = '<div class="search-hint">Type to search across all days and concepts</div>';
    searchActiveIdx = -1;
    return;
  }
  const terms = q.split(/\s+/);
  const results = searchIndex.filter(item =>
    terms.every(t => item.searchText.includes(t))
  ).slice(0, 12);

  if (results.length === 0) {
    container.innerHTML = '<div class="search-no-results">No results for "' + query + '"</div>';
    searchActiveIdx = -1;
    return;
  }

  let html = '';
  results.forEach((r, idx) => {
    // Find a context snippet around the first match
    let snippet = '';
    const firstTerm = terms[0];
    const pos = r.searchText.indexOf(firstTerm);
    if (pos > -1) {
      const start = Math.max(0, pos - 40);
      const end = Math.min(r.searchText.length, pos + firstTerm.length + 60);
      snippet = (start > 0 ? '…' : '') + r.searchText.substring(start, end) + (end < r.searchText.length ? '…' : '');
      terms.forEach(t => {
        snippet = snippet.replace(new RegExp('(' + t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ')', 'gi'), '<mark>$1</mark>');
      });
    }

    html += '<div class="search-result-item' + (idx === 0 ? ' active' : '') + '" data-day="' + r.day + '" onclick="selectSearchResult(' + r.day + ')">';
    html += '<div class="sr-day-num">' + r.day + '</div>';
    html += '<div class="sr-info">';
    html += '<div class="sr-title">' + r.title + '</div>';
    html += '<div class="sr-module">Module ' + r.moduleId + ': ' + r.module + '</div>';
    if (snippet) html += '<div class="sr-match">' + snippet + '</div>';
    html += '</div></div>';
  });
  container.innerHTML = html;
  searchActiveIdx = 0;
}

function selectSearchResult(day) {
  closeSearch();
  loadDay(day);
}

function navigateSearchResults(dir) {
  const items = document.querySelectorAll('.search-result-item');
  if (items.length === 0) return;
  items.forEach(i => i.classList.remove('active'));
  searchActiveIdx = Math.max(0, Math.min(items.length - 1, searchActiveIdx + dir));
  items[searchActiveIdx].classList.add('active');
  items[searchActiveIdx].scrollIntoView({ block: 'nearest' });
}

function confirmSearchResult() {
  const items = document.querySelectorAll('.search-result-item');
  if (searchActiveIdx >= 0 && searchActiveIdx < items.length) {
    const day = parseInt(items[searchActiveIdx].dataset.day);
    selectSearchResult(day);
  }
}

// ─── DARK MODE ───────────────────────────────────────────
function initDarkMode() {
  const isLight = localStorage.getItem('qm_light_mode') === 'true';
  if (isLight) {
    document.body.classList.add('light-mode');
    const btn = document.getElementById('dark-toggle');
    if (btn) btn.textContent = '☾';
  }
}
function toggleDarkMode() {
  const isLight = document.body.classList.toggle('light-mode');
  localStorage.setItem('qm_light_mode', isLight ? 'true' : 'false');
  const btn = document.getElementById('dark-toggle');
  if (btn) btn.textContent = isLight ? '☾' : '☀';
}

// ─── QUIZ STATE ──────────────────────────────────────────
let quizDay = 0;
let quizQuestions = [];
let quizIndex = 0;
let quizScore = 0;

function showQuiz(day) {
  const days = getTrackDays();
  const d = days[day];
  if (!d || !d.problems || d.problems.length === 0) return;

  quizDay = day;
  quizIndex = 0;
  quizScore = 0;
  // Pick up to 2 problems, prefer 1 basic + 1 jane_street
  const basic = d.problems.filter(p => p.type === 'basic');
  const js = d.problems.filter(p => p.type === 'jane_street');
  quizQuestions = [];
  if (basic.length > 0) quizQuestions.push(basic[0]);
  if (js.length > 0) quizQuestions.push(js[0]);
  if (quizQuestions.length === 0) quizQuestions = d.problems.slice(0, 2);

  const mod = MODULES[d.module - 1];
  document.getElementById('quiz-subtitle').textContent = 'Day ' + day + ' · ' + mod.name;
  renderQuizQuestion();
  document.getElementById('quiz-overlay').style.display = 'flex';
}

function renderQuizQuestion() {
  const q = quizQuestions[quizIndex];
  const total = quizQuestions.length;
  const pct = (quizIndex / total) * 100;

  document.getElementById('quiz-qnum').textContent = 'Question ' + (quizIndex + 1) + ' of ' + total;
  document.getElementById('quiz-progress-fill').style.width = pct + '%';
  document.getElementById('quiz-question').innerHTML = q.q;
  document.getElementById('quiz-reveal-btn').style.display = 'block';
  document.getElementById('quiz-answer-box').style.display = 'none';
  // Re-render math in quiz
  if (window.renderMathInElement) {
    setTimeout(() => renderMathInElement(document.getElementById('quiz-overlay'), {
      delimiters: [{left:'$$',right:'$$',display:true},{left:'$',right:'$',display:false}]
    }), 50);
  }
}

function revealQuizAnswer() {
  const q = quizQuestions[quizIndex];
  document.getElementById('quiz-answer-content').innerHTML = q.a;
  document.getElementById('quiz-answer-box').style.display = 'block';
  document.getElementById('quiz-reveal-btn').style.display = 'none';
  if (window.renderMathInElement) {
    setTimeout(() => renderMathInElement(document.getElementById('quiz-answer-box'), {
      delimiters: [{left:'$$',right:'$$',display:true},{left:'$',right:'$',display:false}]
    }), 50);
  }
}

function quizEval(correct) {
  if (correct) quizScore++;
  quizIndex++;
  if (quizIndex < quizQuestions.length) {
    renderQuizQuestion();
  } else {
    // Quiz done — save score and close
    const key = 'qm_quiz_' + currentTrack + '_' + quizDay;
    const prev = JSON.parse(localStorage.getItem(key) || '{"best":0,"attempts":0}');
    prev.best = Math.max(prev.best, quizScore);
    prev.attempts = (prev.attempts || 0) + 1;
    prev.total = quizQuestions.length;
    localStorage.setItem(key, JSON.stringify(prev));
    closeQuiz();
    showQuizToast(quizScore, quizQuestions.length);
    buildModuleNav();
    updateProgress();
  }
}

function closeQuiz() {
  document.getElementById('quiz-overlay').style.display = 'none';
}

function showQuizToast(score, total) {
  const pct = Math.round(score / total * 100);
  const msg = pct === 100 ? '⭐ Perfect score! Day mastered.' :
              pct >= 50  ? '✓ Good — ' + score + '/' + total + ' correct. Keep going.' :
                           'Day logged. Review the answers and try again.';
  const toast = document.getElementById('quiz-toast');
  toast.textContent = msg;
  toast.style.display = 'block';
  setTimeout(() => { toast.style.display = 'none'; }, 3500);
}

function getQuizScore(day) {
  const key = 'qm_quiz_' + currentTrack + '_' + day;
  const data = localStorage.getItem(key);
  if (!data) return null;
  return JSON.parse(data);
}

