    { title:'Blitzstein: Appendix — Measure Theory', url:'file:///C:/Users/17084/Desktop/Quant Resources/Introduction%20to%20Probability%20by%20Joseph%20K.%20Blitzstein%2C%20Jessica%20Hwang%20(z-lib.org).pdf', type:'📖 Local PDF', desc:'Gentle intro to measure-theoretic probability for the Harvard course' },
    { title:'Lawler Ch. 1: Review of Probability', url:'file:///C:/Users/17084/Desktop/Quant Resources/Lawler%20Clac.pdf', type:'📖 Local PDF', desc:'Rigorous probability foundations used in stochastic calculus' }
