    { title:'Chan Ch. 7: Strategy Robustness', url:'file:///C:/Users/17084/Desktop/Quant Resources/Chan%20-%20Algorithmic%20Trading.pdf', type:'📖 Local PDF', desc:'Crisis periods in backtests, regime-conditional strategies, drawdown management' }
